function checkIsValidType(
  valueType: string,
  valueTextValue: string,
  validTypes: (FilterFieldPrimitive | string)[],
  parserConfig?: FilterFieldProps['parserConfig'],
  customTypes?: FilterFieldCustomTypes,
): boolean {
  return (
    validTypes.includes('Any') ||
    validTypes.includes(valueType as FilterFieldPrimitive) ||
    (validTypes.includes('String') && valueType === 'Identifier') ||
    (validTypes.includes('Number') && valueType === 'BigInt') ||
    isValidIPAddressType(valueType, valueTextValue, validTypes, parserConfig) ||
    isValidUIDType(valueType, valueTextValue, validTypes, parserConfig) ||
    isValidSmartscapeIdType(
      valueType,
      valueTextValue,
      validTypes,
      parserConfig,
    ) ||
    isValidTimestampType(valueType, valueTextValue, validTypes, parserConfig) ||
    !!isValidCustomType(valueTextValue, customTypes)
  );
}

function hasValuePredicate(
  entry: FilterFieldCustomTypes[string],
): entry is { valuePredicate: (value: string) => boolean } {
  return (
    !!entry &&
    typeof entry === 'object' &&
    typeof entry.valuePredicate === 'function'
  );
}

/**
 * Returns the type name when the value is of a custom type.
 */
export function isValidCustomType(
  textValue: string,
  customTypes?: FilterFieldCustomTypes,
): string | boolean {
  if (!customTypes) {
    return false;
  }

  for (const [typeName, validatorFn] of Object.entries(customTypes)) {
    if (typeof validatorFn === 'function') {
      if (validatorFn(textValue)) {
        return typeName;
      }
      continue;
    }

    if (
      hasValuePredicate(validatorFn) &&
      validatorFn.valuePredicate(textValue)
    ) {
      return typeName;
    }
  }

  return false;
}

/**
 * checks whether an operator is valid based on the FilterField validatormap
 * @internal
 */
export function isValidOperator(
  textValue: string,
  key: string | undefined,
  internalValidatorMap: InternalValidatorMap | undefined,
  parserConfig?: FilterFieldProps['parserConfig'],
): boolean {
  const operatorName = getOperatorName(textValue);

  if (operatorName === '') {
    return false;
  }

  // If search is not enabled in the filter field, search operators are already
  // marked as errors with a more general error message. To not add an additional
  // error message, search operators are always considered valid here.
  // eslint-disable-next-line @typescript-eslint/no-deprecated
  if (operatorName === 'search' && !parserConfig?.searchConversion) {
    return true;
  }

  return getValidOperators(key, internalValidatorMap, parserConfig).includes(
    operatorName,
  );
}

/**
 * checks whether a value is valid based on the FilterField validatormap
 * @internal
 */
export function isValidValue(
  key: string | undefined,
  valueTextValue: string,
  valueType: string,
  internalValidatorMap: InternalValidatorMap | undefined,
  currentStatement: FilterFieldStatementNode,
  filterFieldValue: string,
  customTypes?: FilterFieldCustomTypes,
  parserConfig?: FilterFieldProps['parserConfig'],
): {
  isValid: boolean;
  message?: string;
  validTypes?: (FilterFieldPrimitive | string)[];
} {
  if (!key || !internalValidatorMap) {
    return { isValid: true };
  }

  const predicate = internalValidatorMap.normalizedKeys.byKey.get(key);

  // No key predicate for the given key - assume value is valid.
  if (!predicate) {
    return { isValid: true };
  }

  const validValues = predicate.valuePredicate;

  if (typeof validValues === 'function') {
    const result = validValues({
      currentStatement,
      filterFieldValue,
    });

    if (typeof result === 'boolean') {
      return { isValid: result };
    }

    return { isValid: false, message: result };
  }

  // If the value is a variable we don't have any further information on what
  // the actual type is, so we skip the type-based validation below.
  // Function predicates above are still called as users can do their own checks.
  if (valueType === 'Variable') {
    return { isValid: true };
  }

  // Determine valid types — predicate.valueType takes precedence over inference from valuePredicate.
  // DEPRECATION: [APPDEV-16872] BREAKING-CHANGE
  // TODO: The valueType inference fallback can be removed once the deprecated FilterFieldValidatorMapTypePredicate format is removed.
  let validTypes: (FilterFieldPrimitive | string)[];
  let hasLiteralValues: boolean;

  if (predicate.valueType) {
    validTypes = Array.isArray(predicate.valueType)
      ? predicate.valueType
      : [predicate.valueType];
    hasLiteralValues = Array.isArray(validValues);
  } else if (validValues !== undefined) {
    // Infer valid types from valuePredicate if valueType is not explicitly configured.
    ({ types: validTypes, hasLiteralValues } = getValidValueTypes(validValues));
  } else {
    // Neither valuePredicate nor valueType configured — any value is valid.
    return { isValid: true };
  }

  const isValidType = checkIsValidType(
    valueType,
    valueTextValue,
    validTypes,
    parserConfig,
    customTypes,
  );

  if (Array.isArray(validValues)) {
    let textMatches = false;

    for (const validValue of validValues) {
      if (isFilterFieldValidatorMapTypeSpecification(validValue)) {
        if ((!isValidType && !hasLiteralValues) || isValidType) {
          return { isValid: isValidType, validTypes };
        }
      } else if (isFilterFieldValueSuggestionGroupConfig(validValue)) {
        if (
          validValue.suggestions.some((suggestion) => {
            if (isFilterFieldValidatorMapTypeSpecification(suggestion)) {
              return false;
            }

            return literalMatchesTextValue(valueTextValue, suggestion);
          })
        ) {
          textMatches = true;
        }

        continue;
      } else if (literalMatchesTextValue(valueTextValue, validValue)) {
        textMatches = true;
      }
    }

    return {
      isValid: textMatches || isWildCardOperator(currentStatement),
      validTypes,
    };
  }

  if (isFilterFieldValidatorMapTypeSpecification(validValues)) {
    return { isValid: isValidType, validTypes };
  }

  if (isFilterFieldValueSuggestionGroupConfig(validValues)) {
    const groupSuggestionMatches = validValues.suggestions.some(
      (suggestion) => {
        if (isFilterFieldValidatorMapTypeSpecification(suggestion)) {
          return false;
        }

        return literalMatchesTextValue(valueTextValue, suggestion);
      },
    );
    return {
      isValid: groupSuggestionMatches || isWildCardOperator(currentStatement),
    };
  }

  // validValues may be undefined when only config.valueType is set.
  if (validValues === undefined) {
    return { isValid: isValidType };
  }

  return {
    isValid: literalMatchesTextValue(valueTextValue, validValues),
    validTypes,
  };
}

/**
 * Checks whether a literal predicate value (string, number, boolean, or duration)
 * matches the given filter field text value after stripping escape backslashes.
 */
function literalMatchesTextValue(
  textValue: string,
  predicate: FilterFieldValuePredicateItem,
): boolean {
  if (isFilterFieldValidatorMapDurationSpecification(predicate)) {
    return textValue === `${predicate.value}${predicate.unit}`;
  }
  if (isFilterFieldRichValuePredicate(predicate)) {
    const cleaned = `${predicate.value}`
      .replaceAll(/(?<!\\)(?:\\\\)*(\\)(?!\\)/g, '')
      .replaceAll(/(\\\\)/g, '\\');

    return textValue === cleaned;
  }
  // The predicate string includes backslashes as provided in the validator map.
  // Single backslashes are removed and double backslashes are converted to single
  // backslashes to match the parsed text value.
  const cleaned = `${predicate}`
    .replaceAll(/(?<!\\)(?:\\\\)*(\\)(?!\\)/g, '')
    .replaceAll(/(\\\\)/g, '\\');
  return textValue === cleaned;
}

/**
 * Returns the textvalue of a filterfield value predicate that is neither a function nor an array.
 * @internal
 */
export function getValuePredicateTextValue(
  predicate: FilterFieldValuePredicateItem,
) {
  if (isFilterFieldValidatorMapDurationSpecification(predicate)) {
    return `${predicate.value}${predicate.unit}`;
  } else if (isFilterFieldRichValuePredicate(predicate)) {
    return `${predicate.value}`;
  } else {
    return `${predicate}`;
  }
}

/**
 * Returns valid operators for the given key.
 * @internal
 */
export function getValidOperators(
  key: string | undefined,
  internalValidatorMap: InternalValidatorMap | undefined,
  parserConfig?: FilterFieldProps['parserConfig'],
): FilterFieldComparisonOperators[] {
  key =
    typeof key === 'string'
      ? key.replace(/^"(.*?(?<!\\)(?:\\\\)*)"$/, '$1')
      : key;

  const defaultOperators: FilterFieldComparisonOperators[] = [
    ...FILTERFIELD_DEFAULT_OPERATORS,
    // eslint-disable-next-line @typescript-eslint/no-deprecated
    ...(parserConfig?.searchConversion
      ? (['search'] as FilterFieldComparisonOperators[])
      : []),
  ];

  if (!internalValidatorMap) {
    return defaultOperators;
  }

  const globalOperators =
    internalValidatorMap.comparisonOperators || defaultOperators;

  const predicate = key
    ? internalValidatorMap.normalizedKeys.byKey.get(key)
    : undefined;

  // Incomplete search operator, we don´t want to show operator suggestions.
  if (!predicate && key === '*') {
    return [];
  }

  if (!predicate) {
    return globalOperators;
  }

  // Early exit if explicit operators are defined for the key.
  if (predicate.comparisonOperators) {
    return predicate.comparisonOperators;
  }

  // Determine allowed types. Explicit valueType takes precedence over valuePredicate inference.
  let allowedTypes: (FilterFieldPrimitive | string)[] | 'Any';
  if (predicate.valueType) {
    allowedTypes = Array.isArray(predicate.valueType)
      ? predicate.valueType
      : [predicate.valueType];
  } else if (
    !predicate.valuePredicate ||
    typeof predicate.valuePredicate === 'function'
  ) {
    allowedTypes = 'Any';
  } else {
    allowedTypes = getValidValueTypes(predicate.valuePredicate).types;
  }

  if (allowedTypes !== 'Any') {
    return intersectOperators(
      globalOperators,
      allowedTypes.reduce((acc: FilterFieldComparisonOperators[], type) => {
        acc.push(...getAllowedOperatorsForType(type));
        return acc;
      }, []),
    );
  }

  return globalOperators;
}

/**
 * Maps operator names to their short names.
 */
const OPERATOR_SHORT_NAME_MAP: Record<string, string> = {
  equals: '=',
  'not-equals': '!=',
  'less-than': '<',
  'less-or-equal': '<=',
  'greater-than': '>',
  'greater-or-equal': '>=',
  'matches-phrase': '~',
  'not-matches-phrase': '!~',
  in: 'in',
  'not in': 'not in',
  contains: 'contains',
  'starts-with': 'starts-with',
  'ends-with': 'ends-with',
  'not-starts-with': 'not-starts-with',
  'not-contains': 'not-contains',
  'not-ends-with': 'not-ends-with',
  exists: '= *',
  'not-exists': '!= *',
};

/**
 * Returns valid operator short names
 * @internal
 */
export function getValidOperatorsShort(
  key: string | undefined,
  internalValidatorMap: InternalValidatorMap | undefined,
  parserConfig: FilterFieldProps['parserConfig'],
) {
  const operators = getValidOperators(key, internalValidatorMap, parserConfig);
  const result: string[] = [];

  for (const [key, value] of Object.entries(OPERATOR_SHORT_NAME_MAP)) {
    if (operators.includes(key as FilterFieldComparisonOperators)) {
      result.push(value);
    }
  }

  return result;
}

/**
 * Lists valid operator short names (syntax colored, comma separated)
 * @internal
 */
export function getValidOperatorsColored(
  key: string | undefined,
  internalValidatorMap: InternalValidatorMap | undefined,
  parserConfig: FilterFieldProps['parserConfig'],
) {
  return getValidOperatorsShort(key, internalValidatorMap, parserConfig)
    .map(
      (operator) =>
        `<span style="color: ${Colors.Syntax.Operators}">${operator}</span>`,
    )
    .join(', ');
}

/**
 * Get colored search operator
 * @internal
 */
export function getColoredSearchOperator() {
  return `<span style="color: ${Colors.Syntax.Variable}">*</span> <span style="color: ${Colors.Syntax.Operators}">~</span>`;
}

function intersectOperators(
  globalOperators: FilterFieldComparisonOperators[],
  operators: FilterFieldComparisonOperators[],
) {
  return globalOperators.filter((op) => operators.includes(op));
}
